"use client"



import { useEffect, useState, useRef } from "react"

import {

  LineChart,

  Line,

  XAxis,

  YAxis,

  Tooltip,

  CartesianGrid,

  ResponsiveContainer

} from "recharts"



type Temp = {

  id: number

  temperatura: number

  createdAt: string

}



const LIMITE_MIN = 2

const LIMITE_MAX = 8



export default function Dashboard() {

  const [data, setData] = useState<Temp[]>([])

  const [loading, setLoading] = useState(true)

  const [startDate, setStartDate] = useState("")

  const [endDate, setEndDate] = useState("")

  const [alarmEnabled, setAlarmEnabled] = useState(false)

  const alarmRef = useRef<HTMLAudioElement | null>(null)



  const fetchData = async () => {

    let url = "/api/temperaturas"

    if (startDate && endDate)

      url += `?start=${startDate}&end=${endDate}`



    const res = await fetch(url)

    const json = await res.json()



    setData(json)

    setLoading(false)

  }



  // 🔁 Polling a cada 100 segundos

  useEffect(() => {

    fetchData()

    const interval = setInterval(fetchData, 100000)

    return () => clearInterval(interval)

  }, [startDate, endDate])  // ← Atualiza quando filtros mudam



  const temperaturas = data.map(d => d.temperatura)

  const current = temperaturas.at(-1)



  const outOfRange =

    current !== undefined &&

    (current < LIMITE_MIN || current > LIMITE_MAX)



  // 🔔 Alarme sonoro

  useEffect(() => {

    if (outOfRange && alarmEnabled && alarmRef.current) {

      alarmRef.current.play().catch(e => console.log('Alarme bloqueado:', e))

    }

  }, [outOfRange, alarmEnabled])



  // 🎵 Habilitar alarme (requer interação do usuário)

  const enableAlarm = () => {

    if (alarmRef.current) {

      alarmRef.current.play().then(() => {

        alarmRef.current?.pause()

        setAlarmEnabled(true)

      }).catch(e => console.log('Erro ao habilitar alarme:', e))

    }

  }



  // 🧠 Tempo fora da faixa

  const tempoForaFaixa = () => {

    let total = 0



    for (let i = 1; i < data.length; i++) {

      const prev = data[i - 1]

      const curr = data[i]



      if (

        prev.temperatura < LIMITE_MIN ||

        prev.temperatura > LIMITE_MAX

      ) {

        const diff =

          new Date(curr.createdAt).getTime() -

          new Date(prev.createdAt).getTime()



        total += diff

      }

    }



    return (total / 1000 / 60).toFixed(2) // minutos

  }



  return (

    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100">

      {/* Header */}

      <div className="bg-white shadow-sm border-b border-slate-200">

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

          <div className="flex justify-between items-center py-6">

            <div>

              <h1 className="text-3xl font-bold text-slate-900">

                Monitoramento de Medicamentos

              </h1>

              <p className="text-slate-600 mt-1">Geladeira - Controle de Temperatura</p>

            </div>

            <div className="flex items-center gap-4">

              <button

                onClick={enableAlarm}

                className={`px-6 py-3 rounded-lg font-medium transition-all ${

                  alarmEnabled 

                    ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/25' 

                    : 'bg-slate-600 text-white hover:bg-slate-700'

                }`}

              >

                {alarmEnabled ? '🔔 Alarme Ativado' : '🔕 Ativar Alarme'}

              </button>

            </div>

          </div>

        </div>

      </div>



      {/* Alert Banner */}

      {outOfRange && (

        <div className="bg-gradient-to-r from-red-600 to-red-700 text-white">

          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">

            <div className="flex items-center gap-3">

              <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>

              <span className="font-medium">⚠️ ALERTA CRÍTICO: Temperatura fora da faixa segura!</span>

            </div>

          </div>

        </div>

      )}



      {/* Main Content */}

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        

        {/* Stats Grid */}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">

          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 hover:shadow-md transition-shadow">

            <div className="flex items-center justify-between">

              <div>

                <p className="text-sm font-medium text-slate-600">Temperatura Atual</p>

                <p className={`text-3xl font-bold mt-2 ${

                  outOfRange ? 'text-red-600' : 'text-slate-900'

                }`}>

                  {current ?? "--"}°C

                </p>

              </div>

              <div className={`w-12 h-12 rounded-full flex items-center justify-center ${

                outOfRange ? 'bg-red-100' : 'bg-emerald-100'

              }`}>

                <span className={`text-xl ${outOfRange ? 'text-red-600' : 'text-emerald-600'}`}>

                  {outOfRange ? '🌡️' : '✅'}

                </span>

              </div>

            </div>

          </div>



          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 hover:shadow-md transition-shadow">

            <div className="flex items-center justify-between">

              <div>

                <p className="text-sm font-medium text-slate-600">Tempo Fora da Faixa</p>

                <p className="text-3xl font-bold mt-2 text-slate-900">

                  {tempoForaFaixa()} min

                </p>

              </div>

              <div className="w-12 h-12 rounded-full bg-amber-100 flex items-center justify-center">

                <span className="text-xl text-amber-600">⏱️</span>

              </div>

            </div>

          </div>



          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 hover:shadow-md transition-shadow">

            <div className="flex items-center justify-between">

              <div>

                <p className="text-sm font-medium text-slate-600">Total de Leituras</p>

                <p className="text-3xl font-bold mt-2 text-slate-900">{data.length}</p>

              </div>

              <div className="w-12 h-12 rounded-full bg-blue-100 flex items-center justify-center">

                <span className="text-xl text-blue-600">📊</span>

              </div>

            </div>

          </div>



          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 hover:shadow-md transition-shadow">

            <div className="flex items-center justify-between">

              <div>

                <p className="text-sm font-medium text-slate-600">Status do Sistema</p>

                <p className={`text-xl font-bold mt-2 ${

                  outOfRange ? 'text-red-600' : 'text-emerald-600'

                }`}>

                  {outOfRange ? 'CRÍTICO' : 'NORMAL'}

                </p>

              </div>

              <div className={`w-12 h-12 rounded-full flex items-center justify-center ${

                outOfRange ? 'bg-red-100' : 'bg-emerald-100'

              }`}>

                <span className={`text-xl ${outOfRange ? 'text-red-600' : 'text-emerald-600'}`}>

                  {outOfRange ? '⚠️' : '🟢'}

                </span>

              </div>

            </div>

          </div>

        </div>



        {/* Chart and Filters Row */}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          

          {/* Chart - Takes 2 columns */}

          <div className="lg:col-span-2">

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">

              <div className="flex justify-between items-center mb-6">

                <h2 className="text-lg font-semibold text-slate-900">Gráfico de Temperatura</h2>

                <div className="flex items-center gap-2 text-sm text-slate-600">

                  <div className="w-3 h-3 bg-blue-600 rounded-full"></div>

                  <span>Temperatura (°C)</span>

                </div>

              </div>

              <div className="h-80">

                <ResponsiveContainer width="100%" height="100%">

                  <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>

                    <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />

                    <XAxis 

                      dataKey="createdAt"

                      tickFormatter={(v) => new Date(v).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}

                      stroke="#64748b"

                      fontSize={12}

                    />

                    <YAxis 

                      domain={[0, 15]} 

                      stroke="#64748b"

                      fontSize={12}

                      label={{ value: 'Temperatura (°C)', angle: -90, position: 'insideLeft' }}

                    />

                    <Tooltip

                      contentStyle={{

                        backgroundColor: 'white',

                        border: '1px solid #e2e8f0',

                        borderRadius: '8px',

                        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'

                      }}

                      labelFormatter={(v) => new Date(v).toLocaleString('pt-BR')}

                      formatter={(value: any) => [`${value}°C`, 'Temperatura']}

                    />

                    <Line

                      type="monotone"

                      dataKey="temperatura"

                      stroke="#1e40af"

                      strokeWidth={3}

                      dot={{ fill: '#1e40af', r: 4 }}

                      activeDot={{ r: 6 }}

                    />

                    {/* Reference lines for limits */}

                    <Line

                      type="monotone"

                      dataKey={() => LIMITE_MAX}

                      stroke="#ef4444"

                      strokeWidth={2}

                      strokeDasharray="5 5"

                      dot={false}

                      name="Limite Máximo"

                    />

                    <Line

                      type="monotone"

                      dataKey={() => LIMITE_MIN}

                      stroke="#ef4444"

                      strokeWidth={2}

                      strokeDasharray="5 5"

                      dot={false}

                      name="Limite Mínimo"

                    />

                  </LineChart>

                </ResponsiveContainer>

              </div>

            </div>

          </div>



          {/* Filters Panel - Takes 1 column */}

          <div className="lg:col-span-1">

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">

              <h2 className="text-lg font-semibold text-slate-900 mb-6">Filtros e Ações</h2>

              

              <div className="space-y-6">

                {/* Date Range Filter */}

                <div>

                  <label className="block text-sm font-medium text-slate-700 mb-3">Período de Análise</label>

                  <div className="space-y-3">

                    <div>

                      <label className="block text-xs text-slate-600 mb-1">Data Inicial</label>

                      <input 

                        type="datetime-local"

                        onChange={e => setStartDate(e.target.value)}

                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"

                      />

                    </div>

                    <div>

                      <label className="block text-xs text-slate-600 mb-1">Data Final</label>

                      <input 

                        type="datetime-local"

                        onChange={e => setEndDate(e.target.value)}

                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"

                      />

                    </div>

                  </div>

                </div>



                {/* Action Buttons */}

                <div className="space-y-3">

                  <button

                    onClick={fetchData}

                    className="w-full bg-blue-600 text-white px-4 py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors shadow-sm"

                  >

                    🔄 Aplicar Filtros

                  </button>

                  

                  <button

                    onClick={() => {

                      setStartDate("")

                      setEndDate("")

                      fetchData()

                    }}

                    className="w-full bg-slate-100 text-slate-700 px-4 py-3 rounded-lg font-medium hover:bg-slate-200 transition-colors"

                  >

                    🗑️ Limpar Filtros

                  </button>



                  <button

                    onClick={() => window.open("/api/relatorio")}

                    className="w-full bg-emerald-600 text-white px-4 py-3 rounded-lg font-medium hover:bg-emerald-700 transition-colors shadow-sm"

                  >

                    📄 Exportar Relatório

                  </button>

                </div>



                {/* Info Panel */}

                <div className="bg-slate-50 rounded-lg p-4">

                  <h3 className="text-sm font-medium text-slate-700 mb-2">Faixa Segura</h3>

                  <div className="space-y-1 text-xs text-slate-600">

                    <div className="flex justify-between">

                      <span>Mínimo:</span>

                      <span className="font-medium">{LIMITE_MIN}°C</span>

                    </div>

                    <div className="flex justify-between">

                      <span>Máximo:</span>

                      <span className="font-medium">{LIMITE_MAX}°C</span>

                    </div>

                  </div>

                  {!alarmEnabled && (

                    <div className="mt-3 pt-3 border-t border-slate-200">

                      <p className="text-xs text-amber-600">

                        💡 Ative o alarme sonoro para notificações

                      </p>

                    </div>

                  )}

                </div>

              </div>

            </div>

          </div>

        </div>

      </div>



      <audio ref={alarmRef} src="/alarm.mp3" />

    </div>

  )

}



function Card({ title, value }: any) {

  return (

    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 hover:shadow-md transition-shadow">

      <div className="flex items-center justify-between">

        <div>

          <p className="text-sm font-medium text-slate-600">{title}</p>

          <p className="text-3xl font-bold mt-2 text-slate-900">{value}</p>

        </div>

        <div className="w-12 h-12 rounded-full bg-blue-100 flex items-center justify-center">

          <span className="text-xl text-blue-600">📊</span>

        </div>

      </div>

      <h3 className="text-sm text-gray-500">{title}</h3>

      <p className="text-2xl font-bold mt-2">{value}</p>

    </div>

  )

}